import json
import os
import boto3

s3 = boto3.client("s3")
dynamodb = boto3.resource("dynamodb")
sns = boto3.client("sns")
sqs = boto3.client("sqs")

def lambda_handler(event, context):
    bucket = os.environ.get("BUCKET_NAME")
    table_name = os.environ.get("TABLE_NAME")
    topic_arn = os.environ.get("TOPIC_ARN")
    queue_url = os.environ.get("QUEUE_URL")

    response = {
        "statusCode": 200,
        "body": json.dumps({
            "message": "Lambda executed successfully",
            "received_event": event
        })
    }

    if bucket:
        s3.put_object(Bucket=bucket, Key="lambda/healthcheck.txt", Body=b"ok")

    if table_name:
        table = dynamodb.Table(table_name)
        table.put_item(Item={
            "pk": "healthcheck",
            "sk": "lambda",
            "status": "ok"
        })

    if topic_arn:
        sns.publish(
            TopicArn=topic_arn,
            Message=json.dumps({"message": "Lambda healthcheck"}),
            Subject="Lambda Notification"
        )

    if queue_url:
        sqs.send_message(
            QueueUrl=queue_url,
            MessageBody=json.dumps({"message": "Lambda healthcheck"})
        )

    return response